// ============================================================
// IUT Events Parser — extracts events from iutripura.edu.in
// HTML structure: <li class="item"> containing
//   <h4 class="sub-title">  → title
//   <p class="text">        → description
//   <em>Event Date: ...</em> → date
//   <a href="/Home/EventsDetails/ID"> → detail link
// ============================================================

const html = $input.first().json.data || '';
const events = [];
const seen = new Set();

// Helper: strip HTML tags
const strip = (s) => s
  .replace(/<[^>]+>/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&nbsp;/g, ' ')
  .replace(/&quot;/g, '"')
  .replace(/&#\d+;/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Determine forthcoming vs concluded boundary
const forthIdx = html.toLowerCase().indexOf('forthcoming');
const conclIdx = html.toLowerCase().indexOf('concluded');

// Find all event <li class="item"> blocks
const itemRegex = /<li\s+class="item"[^>]*>([\s\S]*?)<\/li>/gi;
let itemMatch;

while ((itemMatch = itemRegex.exec(html)) !== null && events.length < 50) {
  const block = itemMatch[1];
  const blockPos = itemMatch.index;

  // Extract detail link and event ID
  const linkMatch = block.match(/href\s*=\s*["']([^"']*EventsDetails\/(\d+))["']/i);
  if (!linkMatch) continue;
  const eventId = linkMatch[2];
  if (seen.has(eventId)) continue;
  seen.add(eventId);

  const sourceUrl = linkMatch[1].startsWith('http')
    ? linkMatch[1]
    : 'https://iutripura.edu.in' + linkMatch[1];

  // Extract title from <h4 class="sub-title">
  const titleMatch = block.match(/<h4[^>]*class="[^"]*sub-title[^"]*"[^>]*>([\s\S]*?)<\/h4>/i)
    || block.match(/<h[2-6][^>]*>([\s\S]*?)<\/h[2-6]>/i);
  const title = titleMatch ? strip(titleMatch[1]) : 'Untitled Event';

  // Extract description from <p class="text">
  const descMatch = block.match(/<p[^>]*class="[^"]*text[^"]*"[^>]*>([\s\S]*?)<\/p>/i)
    || block.match(/<p[^>]*>([\s\S]*?)<\/p>/i);
  const description = descMatch ? strip(descMatch[1]) : title;

  // Extract date from <em>Event Date: ...</em>
  const dateMatch = block.match(/Event\s*Date\s*:?\s*([A-Za-z]{3,9}\s+\d{1,2}\s*,?\s*\d{4})/i);
  let startTime = null;
  if (dateMatch) {
    try { startTime = new Date(dateMatch[1].trim()).toISOString(); } catch (e) {}
  }

  // Determine category: forthcoming or concluded
  const isForthcoming = forthIdx >= 0 && (conclIdx < 0 || blockPos < conclIdx);
  const category = isForthcoming ? 'Forthcoming' : 'Concluded';

  // Extract image URL if available
  const imgMatch = block.match(/<img[^>]*src\s*=\s*["']([^"']+)["']/i);
  const imageUrl = imgMatch
    ? (imgMatch[1].startsWith('http') ? imgMatch[1] : 'https://iutripura.edu.in' + imgMatch[1])
    : null;

  events.push({
    json: {
      title: title.substring(0, 300),
      description: description.substring(0, 1000),
      location: 'ICFAI University, Tripura',
      start_time: startTime,
      category: category,
      source_url: sourceUrl
    }
  });
}

return events;
